patterns.codeBlock:
# Check permissions
ls -la {path}
# Fix ownership (replace $USER with your user)
sudo chown -R $USER:$USER {path}
# Fix permissions
chmod 755 {path}

# macOS/Linux: find and kill process on port
lsof -i :{port}
kill -9 $(lsof -t -i :{port})

# Windows:
netstat -ano | findstr :{port}
taskkill /PID <PID> /F

# Check if service is running
curl -v http://{host}:{port}

# Check if port is open
nc -zv {host} {port}

# Test connectivity
ping {target}
curl -v --connect-timeout 10 {target}

# Check DNS
nslookup {target}

// Express.js CORS middleware
const cors = require('cors');
app.use(cors({
  origin: '{origin}',
  methods: ['GET', 'POST', 'PUT', 'DELETE'],
  credentials: true
}));

